import * as Schemas from "database/schemas/";
import { connectMongoClient, connectToS3 } from '../drivers/main-driver';
import fs from 'fs';

const setupDatabase = async () => {
    await connectMongoClient()
    await connectToS3()
    Schemas.build()
    if (!fs.existsSync('data')) await fs.promises.mkdir('data', {recursive: true});
    if (!fs.existsSync('data/files')) await fs.promises.mkdir('data/files', {recursive: true});
    if (!fs.existsSync('data/previews')) await fs.promises.mkdir('data/previews', {recursive: true});
    if (!fs.existsSync('data/temp')) await fs.promises.mkdir('data/temp', {recursive: true});
    if (!fs.existsSync('data/pdf-pages')) await fs.promises.mkdir('data/pdf-pages', {recursive: true});
}

export {
    setupDatabase
}
